     1→// ============================================================================
     2→// Teacher Module - Server-Sent Events
     3→// Real-time updates for teacher dashboard
     4→// ============================================================================
     5→
     6→import fp from 'fastify-plugin';
     7→import { EventEmitter } from 'events';
     8→import { authMiddleware } from '../../middleware/auth.middleware';
     9→import { requireRole } from '../../websocket/ws.auth';
    10→import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
    11→import type { AIMessage } from '../../websocket/ws.types';
    12→
    13→// ============================================================================
    14→// SSE Event Types
    15→// ============================================================================
    16→
    17→interface SSEEvent {
    18→  type: 'violation' | 'attempt_status' | 'exam_start' | 'exam_end' | 'student_action';
    19→  data: Record<string, unknown>;
    20→  timestamp: number;
    21→}
    22→
    23→interface SSEClient {
    24→  userId: number;
    25→  reply: FastifyReply;
    26→  filters: {
    27→    examId?: number;
    28→    userId?: number;
    29→  };
    30→  isConnected: boolean;
    31→}
    32→
    33→// ============================================================================
    34→// SSE Manager
    35→// ============================================================================
    36→
    37→class SSEManager extends EventEmitter {
    38→  private clients = new Map<FastifyReply, SSEClient>();
    39→
    40→  /**
    41→   * Add a new SSE client
    42→   */
    43→  addClient(reply: FastifyReply, userId: number, filters: { examId?: number; userId?: number }): void {
    44→    const client: SSEClient = {
    45→      userId,
    46→      reply,
    47→      filters,
    48→      isConnected: true
    49→    };
    50→
    51→    this.clients.set(reply, client);
    52→
    53→    // Send initial connection event
    54→    this.sendToClient(reply, {
    55→      type: 'student_action',
    56→      data: {
    57→        action: 'connected',
    58→        message: 'Connected to real-time updates'
    59→      },
    60→      timestamp: Date.now()
    61→    });
    62→
    63→    // Handle client disconnect
    64→    reply.raw.on('close', () => {
    65→      this.removeClient(reply);
    66→    });
    67→  }
    68→
    69→  /**
    70→   * Remove a client
    71→   */
    72→  removeClient(reply: FastifyReply): void {
    73→    const client = this.clients.get(reply);
    74→    if (client) {
    75→      client.isConnected = false;
    76→      this.clients.delete(reply);
    77→    }
    78→  }
    79→
    80→  /**
    81→   * Send event to a specific client
    82→   */
    83→  private sendToClient(reply: FastifyReply, event: SSEEvent): boolean {
    84→    const client = this.clients.get(reply);
    85→
    86→    if (!client?.isConnected) {
    87→      return false;
    88→    }
    89→
    90→    try {
    91→      // Format SSE message
    92→      const message = `event: ${event.type}\ndata: ${JSON.stringify(event.data)}\nid: ${event.timestamp}\n\n`;
    93→
    94→      // Write to response
    95→      reply.raw.write(message);
    96→
    97→      return true;
    98→    } catch (error) {
    99→      console.error('Failed to send SSE event:', error);
   100→      this.removeClient(reply);
   101→      return false;
   102→    }
   103→  }
   104→
   105→  /**
   106→   * Broadcast event to all matching clients
   107→   */
   108→  broadcast(event: SSEEvent, filters?: { examId?: number; userId?: number }): void {
   109→    for (const [reply, client] of this.clients.entries()) {
   110→      // Check if client should receive this event
   111→      if (filters?.examId && client.filters.examId && filters.examId !== client.filters.examId) {
   112→        continue;
   113→      }
   114→
   115→      if (filters?.userId && client.filters.userId && filters.userId !== client.filters.userId) {
   116→        continue;
   117→      }
   118→
   119→      this.sendToClient(reply, event);
   120→    }
   121→
   122→    // Also emit for logging/monitoring
   123→    this.emit('broadcast', event, filters);
   124→  }
   125→
   126→  /**
   127→   * Get statistics
   128→   */
   129→  getStats(): {
   130→    totalClients: number;
   131→    connectedClients: number;
   132→  } {
   133→    const connectedClients = Array.from(this.clients.values()).filter(c => c.isConnected).length;
   134→
   135→    return {
   136→      totalClients: this.clients.size,
   137→      connectedClients
   138→    };
   139→  }
   140→
   141→  /**
   142→   * Remove all clients for a specific user
   143→   */
   144→  disconnectUser(userId: number): void {
   145→    for (const [reply, client] of this.clients.entries()) {
   146→      if (client.userId === userId) {
   147→        try {
   148→          reply.raw.end();
   149→        } catch {
   150→          // Ignore errors during cleanup
   151→        }
   152→        this.removeClient(reply);
   153→      }
   154→    }
   155→  }
   156→}
   157→
   158→// ============================================================================
   159→// SSE Routes Plugin
   160→// ============================================================================
   161→
   162→const sseManager = new SSEManager();
   163→
   164→export default fp(async (fastify: FastifyInstance) => {
   165→  // ==========================================================================
   166→  // SSE Endpoint
   167→  // ==========================================================================
   168→
   169→  /**
   170→   * SSE endpoint for real-time updates
   171→   */
   172→  fastify.get('/api/teacher/events', {
   173→    onRequest: [authMiddleware]
   174→  }, async (request: FastifyRequest, reply: FastifyReply) => {
   175→    const user = (request as any).user;
   176→
   177→    // Verify teacher role
   178→    requireRole(user, ['teacher']);
   179→
   180→    // Get filters from query
   181→    const examId = (request.query as any).examId ? parseInt((request.query as any).examId, 10) : undefined;
   182→    const userId = (request.query as any).userId ? parseInt((request.query as any).userId, 10) : undefined;
   183→
   184→    // Set SSE headers
   185→    reply.raw.setHeader('Content-Type', 'text/event-stream');
   186→    reply.raw.setHeader('Cache-Control', 'no-cache');
   187→    reply.raw.setHeader('Connection', 'keep-alive');
   188→    reply.raw.setHeader('X-Accel-Buffering', 'no');
   189→
   190→    // Add client to manager
   191→    sseManager.addClient(reply, user.id, { examId, userId });
   192→
   193→    // Send periodic heartbeat to keep connection alive
   194→    const heartbeatInterval = setInterval(() => {
   195→      try {
   196→        const heartbeatMessage = `event: heartbeat\ndata: ${JSON.stringify({ timestamp: Date.now() })}\nid: ${Date.now()}\n\n`;
   197→        reply.raw.write(heartbeatMessage);
   198→      } catch {
   199→        clearInterval(heartbeatInterval);
   200→      }
   201→    }, 15000); // Every 15 seconds
   202→
   203→    // Cleanup on disconnect
   204→    reply.raw.on('close', () => {
   205→      clearInterval(heartbeatInterval);
   206→    });
   207→
   208→    // Keep connection open
   209→    return reply.raw;
   210→  });
   211→
   212→  // ==========================================================================
   213→  // Test Endpoint (for development)
   214→  // ==========================================================================
   215→
   216→  /**
