     6→import { EventEmitter } from 'events';
     7→import type { ProctoringSession, WSConnection, AIConnection } from './ws.types';
     8→import type { ClientMessage, AIMessage } from './ws.types';
     9→import logger from '../config/logger';
    10→
    11→// ============================================================================
    12→// WebSocket Handler
    13→// ============================================================================
    14→
    15→export class WSHandler extends EventEmitter {
    16→  private sessions = new Map<string, ProctoringSession>();
    17→  private connections = new Map<any, string>(); // socket -> sessionId
    18→
    19→  /**
    20→   * Create a new proctoring session
    21→   */
    22→  createSession(sessionData: {
    23→    attemptId: number;
    24→    userId: number;
    25→    examId: number;
    26→    sessionId: string;
    27→    ipAddress: string;
    28→    userAgent: string;
    29→  }): ProctoringSession {
    30→    const session: ProctoringSession = {
    31→      ...sessionData,
    32→      status: 'starting',
    33→      clientConnection: null,
    34→      aiConnection: null,
    35→      startTime: Date.now(),
    36→      lastActivity: Date.now()
    37→    };
    38→
    39→    this.sessions.set(sessionData.sessionId, session);
    40→    logger.info(`Created proctoring session: ${sessionData.sessionId}`);
    41→
    42→    return session;
    43→  }
    44→
    45→  /**
    46→   * Register client connection
    47→   */
    48→  registerClientConnection(
    49→    socket: any,
    50→    sessionId: string,
    51→    connectionData: {
    52→      userId: number;
    53→      attemptId: number;
    54→      ipAddress: string;
    55→      userAgent: string;
    56→    }
    57→  ): WSConnection {
    58→    const session = this.sessions.get(sessionId);
    59→
    60→    if (!session) {
    61→      throw new Error(`Session not found: ${sessionId}`);
    62→    }
    63→
    64→    const connection: WSConnection = {
    65→      socket,
    66→      userId: connectionData.userId,
    67→      attemptId: connectionData.attemptId,
    68→      sessionId,
    69→      isConnected: true,
    70→      lastFrameSequence: 0,
    71→      framesProcessed: 0,
    72→      startTime: Date.now(),
    73→      ipAddress: connectionData.ipAddress,
    74→      userAgent: connectionData.userAgent
    75→    };
    76→
    77→    session.clientConnection = connection;
    78→    this.connections.set(socket, sessionId);
    79→
    80→    session.status = 'active';
    81→    session.lastActivity = Date.now();
    82→
    83→    this.emit('client:connected', { session, connection });
    84→    logger.info(`Client connected to session: ${sessionId}`);
    85→
    86→    return connection;
    87→  }
    88→
    89→  /**
    90→   * Register AI service connection
    91→   */
    92→  registerAIConnection(socket: any, sessionId: string): AIConnection {
    93→    const session = this.sessions.get(sessionId);
    94→
    95→    if (!session) {
    96→      throw new Error(`Session not found: ${sessionId}`);
    97→    }
    98→
    99→    const connection: AIConnection = {
   100→      socket,
   101→      isConnected: true,
   102→      lastHeartbeat: Date.now(),
   103→      reconnectAttempts: 0
   104→    };
   105→
   106→    session.aiConnection = connection;
   107→    session.lastActivity = Date.now();
   108→
   109→    this.emit('ai:connected', { session, connection });
   110→    logger.info(`AI service connected for session: ${sessionId}`);
   111→
   112→    return connection;
   113→  }
   114→
   115→  /**
   116→   * Handle message from client
   117→   */
   118→  async handleClientMessage(sessionId: string, message: ClientMessage): Promise<void> {
   119→    const session = this.sessions.get(sessionId);
   120→
   121→    if (!session) {
   122→      throw new Error(`Session not found: ${sessionId}`);
   123→    }
   124→
   125→    session.lastActivity = Date.now();
   126→
   127→    if (message.type === 'frame') {
   128→      session.clientConnection!.lastFrameSequence = message.sequence;
   129→      session.clientConnection!.framesProcessed++;
   130→
   131→      // Forward to AI service
   132→      if (session.aiConnection?.isConnected) {
   133→        this.sendToAI(sessionId, message);
   134→      } else {
   135→        // AI not connected, buffer or error
   136→        this.emit('ai:unavailable', { session, message });
   137→      }
   138→    } else if (message.type === 'start' || message.type === 'stop') {
   139→      this.emit('client:control', { session, message });
   140→    } else if (message.type === 'ping') {
   141→      // Respond with pong
   142→      this.sendToClient(sessionId, {
   143→        type: 'status',
   144→        status: 'ready',
   145→        timestamp: Date.now()
   146→      });
   147→    }
   148→  }
   149→
   150→  /**
   151→   * Handle message from AI service
   152→   */
   153→  async handleAIMessage(sessionId: string, message: AIMessage): Promise<void> {
   154→    const session = this.sessions.get(sessionId);
   155→
   156→    if (!session) {
   157→      logger.warn(`Received AI message for unknown session: ${sessionId}`);
   158→      return;
   159→    }
   160→
   161→    session.lastActivity = Date.now();
   162→
   163→    if (message.type === 'violation') {
   164→      // Store violation in database
   165→      this.emit('violation:detected', { session, message });
   166→
   167→      // Forward to client
   168→      this.sendToClient(sessionId, message);
   169→    } else if (message.type === 'status') {
   170→      // Forward status to client
   171→      this.sendToClient(sessionId, message);
   172→    } else if (message.type === 'error') {
   173→      logger.error(`AI error for session ${sessionId}:`, message);
   174→      this.sendToClient(sessionId, message);
   175→    }
   176→  }
   177→
   178→  /**
   179→   * Handle client disconnection
   180→   */
   181→  handleClientDisconnect(socket: any): void {
   182→    const sessionId = this.connections.get(socket);
   183→
   184→    if (!sessionId) {
   185→      return;
   186→    }
   187→
   188→    const session = this.sessions.get(sessionId);
   189→
   190→    if (session?.clientConnection) {
   191→      session.clientConnection.isConnected = false;
   192→      session.clientConnection.socket = null as any;
   193→      session.status = 'stopping';
   194→
   195→      this.emit('client:disconnected', { session });
   196→      logger.info(`Client disconnected from session: ${sessionId}`);
   197→    }
   198→
   199→    this.connections.delete(socket);
   200→  }
   201→
   202→  /**
   203→   * Handle AI disconnection
   204→   */
   205→  handleAIDisconnect(socket: any): void {
   206→    // Find session by AI socket
   207→    for (const [sessionId, session] of this.sessions.entries()) {
   208→      if (session.aiConnection?.socket === socket) {
   209→        session.aiConnection!.isConnected = false;
   210→        session.aiConnection!.socket = null as any;
   211→
   212→        this.emit('ai:disconnected', { session });
   213→        logger.warn(`AI service disconnected for session: ${sessionId}`);
   214→
   215→        // Attempt reconnect
   216→        this.emit('ai:reconnect', { session });
   217→        break;
   218→      }
   219→    }
   220→  }
   221→
   222→  /**
   223→   * Send message to client
   224→   */
   225→  sendToClient(sessionId: string, message: AIMessage): boolean {
   226→    const session = this.sessions.get(sessionId);
   227→
   228→    if (!session?.clientConnection?.isConnected) {
   229→      return false;
   230→    }
   231→
   232→    try {
   233→      session.clientConnection.socket.send(JSON.stringify(message));
   234→      return true;
   235→    } catch (error) {
   236→      logger.error(`Failed to send to client ${sessionId}:`, error);
   237→      return false;
   238→    }
   239→  }
   240→
   241→  /**
   242→   * Send message to AI service
   243→   */
   244→  sendToAI(sessionId: string, message: ClientMessage): boolean {
   245→    const session = this.sessions.get(sessionId);
   246→
   247→    if (!session?.aiConnection?.isConnected) {
   248→      return false;
   249→    }
   250→
   251→    try {
   252→      session.aiConnection.socket.send(JSON.stringify(message));
   253→      return true;
   254→    } catch (error) {
   255→      logger.error(`Failed to send to AI ${sessionId}:`, error);
   256→      return false;
   257→    }
   258→  }
   259→
   260→  /**
   261→   * Broadcast violation to all teacher dashboards
   262→   */
   263→  broadcastViolation(violationData: {
   264→    attemptId: number;
   265→    violation: AIMessage;
   266→  }): void {
   267→    this.emit('violation:broadcast', violationData);
   268→  }
   269→
   270→  /**
   271→   * Get session
   272→   */
   273→  getSession(sessionId: string): ProctoringSession | undefined {
   274→    return this.sessions.get(sessionId);
   275→  }
   276→
   277→  /**
   278→   * Get session by attempt ID
   279→   */
   280→  getSessionByAttempt(attemptId: number): ProctoringSession | undefined {
   281→    for (const session of this.sessions.values()) {
   282→      if (session.attemptId === attemptId) {
   283→        return session;
   284→      }
   285→    }
   286→    return undefined;
   287→  }
   288→
   289→  /**
   290→   * Close session
   291→   */
   292→  async closeSession(sessionId: string): Promise<void> {
   293→    const session = this.sessions.get(sessionId);
   294→
   295→    if (!session) {
   296→      return;
   297→    }
   298→
   299→    // Close client connection
   300→    if (session.clientConnection?.isConnected) {
   301→      try {
   302→        session.clientConnection.socket.close();
   303→      } catch (error) {
   304→        logger.error(`Error closing client socket:`, error);
   305→      }
   306→    }
   307→
   308→    // Close AI connection
   309→    if (session.aiConnection?.isConnected) {
   310→      try {
