     1→// ============================================================================
     2→// Teacher Module - Server-Sent Events
     3→// Real-time updates for teacher dashboard
     4→// ============================================================================
     5→
     6→import fp from 'fastify-plugin';
     7→import { EventEmitter } from 'events';
     8→import { authMiddleware } from '../../middleware/auth.middleware';
     9→import { requireRole } from '../../websocket/ws.auth';
    10→import type { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
    11→import type { AIMessage } from '../../websocket/ws.types';
    12→
    13→// ============================================================================
    14→// SSE Event Types
    15→// ============================================================================
    16→
    17→interface SSEEvent {
    18→  type: 'violation' | 'attempt_status' | 'exam_start' | 'exam_end' | 'student_action';
    19→  data: Record<string, unknown>;
    20→  timestamp: number;
    21→}
    22→
    23→interface SSEClient {
    24→  userId: number;
    25→  reply: FastifyReply;
    26→  filters: {
    27→    examId?: number;
    28→    userId?: number;
    29→  };
    30→  isConnected: boolean;
    31→}
    32→
    33→// ============================================================================
    34→// SSE Manager
    35→// ============================================================================
    36→
    37→class SSEManager extends EventEmitter {
    38→  private clients = new Map<FastifyReply, SSEClient>();
    39→
    40→  /**
    41→   * Add a new SSE client
    42→   */
    43→  addClient(reply: FastifyReply, userId: number, filters: { examId?: number; userId?: number }): void {
    44→    const client: SSEClient = {
    45→      userId,
    46→      reply,
    47→      filters,
    48→      isConnected: true
    49→    };
    50→
    51→    this.clients.set(reply, client);
    52→
    53→    // Send initial connection event
    54→    this.sendToClient(reply, {
    55→      type: 'student_action',
    56→      data: {
    57→        action: 'connected',
    58→        message: 'Connected to real-time updates'
    59→      },
    60→      timestamp: Date.now()
    61→    });
    62→
    63→    // Handle client disconnect
    64→    reply.raw.on('close', () => {
    65→      this.removeClient(reply);
    66→    });
    67→  }
    68→
    69→  /**
    70→   * Remove a client
    71→   */
    72→  removeClient(reply: FastifyReply): void {
    73→    const client = this.clients.get(reply);
    74→    if (client) {
    75→      client.isConnected = false;
    76→      this.clients.delete(reply);
    77→    }
    78→  }
    79→
    80→  /**
    81→   * Send event to a specific client
    82→   */
    83→  private sendToClient(reply: FastifyReply, event: SSEEvent): boolean {
    84→    const client = this.clients.get(reply);
    85→
    86→    if (!client?.isConnected) {
    87→      return false;
    88→    }
    89→
    90→    try {
    91→      // Format SSE message
    92→      const message = `event: ${event.type}\ndata: ${JSON.stringify(event.data)}\nid: ${event.timestamp}\n\n`;
