      isConnected: true,
      lastHeartbeat: Date.now(),
      reconnectAttempts: 0
    };

    session.aiConnection = connection;
    session.lastActivity = Date.now();

    this.emit('ai:connected', { session, connection });
    logger.info(`AI service connected for session: ${sessionId}`);

    return connection;
  }

