interface SSEEvent {
  type: 'violation' | 'attempt_status' | 'exam_start' | 'exam_end' | 'student_action';
  data: Record<string, unknown>;
  timestamp: number;
}

interface SSEClient {
  userId: number;
  reply: FastifyReply;
  filters: {
    examId?: number;
    userId?: number;
  };
  isConnected: boolean;
}

