      mockPool.query = mockFn;
        .mockResolvedValueOnce({ rows: [mockRoom] }) // Get room
        .mockResolvedValueOnce({ rows: [mockActivatedRoom] }); // Update room

      const result = await roomService.activateRoom(1, 1);

