export type StudentStatus = "normal" | "warning" | "suspicious";

export interface Student {
  id: string;
  name: string;
  exam: string;
  status: StudentStatus;
  connection: "Excellent" | "Good" | "Fair" | "Poor";
}

export interface Alert {
