'use client';

import { useEffect, useRef } from 'react';
import { useWebRTC } from '@/hooks/useWebRTC';
import { VideoStream } from './VideoStream';
import { FiLoader } from 'react-icons/fi';

export const  StudentsGrid = () => {
  const roomId = 'exam-monitoring-room';
  const backendUrl = process.env.NEXT_PUBLIC_BACKEND_URL || 'http://localhost:5000';
  const hasAutoJoined = useRef(false);

  // For demo, use teacher as viewer with peerId
  const teacherPeerId = useRef(`teacher-${Date.now()}`);

  const {
    peers,
    streams,
    isConnected,
    error,
    joinRoom,
    leaveRoom,
    getRemoteStreams,
  } = useWebRTC({
    roomId,
    peerId: teacherPeerId.current,
    userId: 0,
    studentName: 'Teacher',
    backendUrl,
  });

  const remoteStreams = getRemoteStreams();
  const videoStreams = remoteStreams.filter(streamInfo => streamInfo.kind === 'video');

  useEffect(() => {
    if (hasAutoJoined.current) {
      return;
    }

    hasAutoJoined.current = true;
    joinRoom().catch(console.error);
  }, [joinRoom]);

  if (error) {
    return (
      <section className="flex flex-col gap-6 px-4">
        <div className="bg-red-50 text-red-800 p-4 rounded-lg">
          <p className="font-semibold">Error</p>
          <p className="text-sm">{error}</p>
        </div>
      </section>
    );
  }

  return (
    <section className="flex flex-col gap-6 px-4">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div className="flex flex-col">
          <h2 className="text-xl font-bold text-gray-900">
            Live Monitoring Dashboard
          </h2>
          <p className="text-sm text-gray-600 mt-1">
            Viewing {peers.length} students in real-time
            {!isConnected && ' (connecting...)'}
          </p>
        </div>

        {/* Status Controls */}
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <div
              className={`h-3 w-3 rounded-full ${
                isConnected ? 'bg-green-500' : 'bg-yellow-500 animate-pulse'
              }`}
            />
            <span className="text-xs font-medium text-gray-700">
              {isConnected ? 'Connected' : 'Connecting'}
            </span>
          </div>

          {/* Connection Stats */}
            <span className="text-xs text-gray-600 bg-gray-100 px-3 py-1 rounded-full">
            {videoStreams.length} active video streams
          </span>
        </div>
      </div>

      {/* Connection Status */}
      {!isConnected && (
        <div className="bg-blue-50 text-blue-800 p-4 rounded-lg flex items-center gap-2">
          <FiLoader className="animate-spin" size={16} />
