                  <VideoStream
                    stream={streamInfo.stream}
                    studentName={peer.studentName}
                    peerId={peer.peerId}
                    isProducing={peer.isProducing}
                    connectionState={peer.connectionState}
                    videoEnabled={peer.videoEnabled}
                    audioEnabled={peer.audioEnabled}
                  />
                )}
              </div>
            );
