          <div className="flex flex-wrap gap-2">
            {peers.map((peer) => (
              <div
                key={peer.peerId}
                className="text-xs bg-blue-100 text-blue-800 px-2 py-1 rounded-full"
              >
                {peer.studentName}
              </div>
            ))}
          </div>
        </div>
      )}
    </section>
  );
};

